const BASE = '/master';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export interface PaginatedList<T> {
  items: T[];
  totalCount: number;
  page: number;
  pageSize: number;
}

type PaginatedApi<T> = {
  items: T[];
  totalCount: number;
  page: number;
  pageSize: number;
};

export type CatalogListParams = {
  search?: string;
  page?: number;
  pageSize?: number;
};

async function getPaginated<T>(
  path: string,
  params?: Record<string, string | number | boolean | undefined>,
): Promise<PaginatedList<T>> {
  const qs = params ? buildQs(params) : '';
  const res = await apiClient.get<BffResponse<PaginatedApi<T>>>(`${path}${qs ? `?${qs}` : ''}`);
  const data = unwrap(res);
  return {
    items: data?.items ?? [],
    totalCount: Number(data?.totalCount ?? 0),
    page: data?.page ?? 1,
    pageSize: data?.pageSize ?? 50,
  };
}

/** @deprecated Prefer getPaginated — unwraps first page items only. */
async function getList<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T[]> {
  const result = await getPaginated<T>(path, { page: 1, pageSize: 500, ...params });
  return result.items;
}

