import React from 'react';
import { CatalogDocumentHistory } from './CatalogDocumentHistory';
import { masterCatalogDocumentType } from '../../config/documentHistoryClients';

export type CatalogFormHistoryRecord = {
  id: string;
  code: string;
};

type CatalogFormHistorySlotProps = {
  testIdPrefix: string;
  catalogKind: string;
  editing: CatalogFormHistoryRecord | null | undefined;
};

/** Step 2u — Lịch sử trên form sửa (modal/footer). */
export function CatalogFormHistorySlot({
  testIdPrefix,
  catalogKind,
  editing,
}: CatalogFormHistorySlotProps): React.ReactElement | null {
  if (!editing?.id) return null;
  const documentType = masterCatalogDocumentType(catalogKind);
  if (!documentType) return null;
  return (
    <CatalogDocumentHistory
      testIdPrefix={testIdPrefix}
      documentType={documentType}
      documentId={editing.id}
      documentCode={editing.code}
    />
  );
}
