/** form-code-field.md — normalize mã trước khi lưu state / gửi API */
export const normalizeCode = (v: string) => v.trim().toUpperCase();

/** Optional mã — undefined khi rỗng sau trim */
export const normalizeCodeOptional = (v?: string) => {
  const s = v?.trim();
  return s ? s.toUpperCase() : undefined;
};

/** Search local: case-insensitive + no-diacritics + collapse spaces. */
export const normalizeSearchText = (value?: string): string => {
  if (!value) return '';
  return value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/g, 'd')
    .replace(/Đ/g, 'D')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
};

/** Client CI filter danh mục (Pattern A) — mã + tên */
export function matchesCodeOrName(
  code: string,
  name: string,
  query: string,
  extra?: string,
): boolean {
  const q = normalizeSearchText(query);
  if (!q) return true;
  const normalizedCode = normalizeSearchText(code);
  const normalizedName = normalizeSearchText(name);
  const normalizedExtra = normalizeSearchText(extra);
  return (
    normalizedCode.includes(q)
    || normalizedName.includes(q)
    || normalizedExtra.includes(q)
  );
}
